import sqlite3
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]


def read_sql(name):
    return (ROOT / "sql" / name).read_text(encoding="ascii")


def make_db():
    db = sqlite3.connect(":memory:")
    db.executescript(
        """
        CREATE TABLE email_recipient (
            recipient_id INTEGER PRIMARY KEY,
            campaign_key TEXT NOT NULL,
            address TEXT NOT NULL,
            enabled INTEGER NOT NULL CHECK (enabled IN (0, 1))
        );

        CREATE TABLE email_suppression (
            suppression_id INTEGER PRIMARY KEY,
            campaign_key TEXT NOT NULL,
            recipient_id INTEGER,
            reason TEXT NOT NULL
        );

        CREATE TABLE webhook_delivery (
            delivery_id INTEGER PRIMARY KEY,
            topic_key TEXT NOT NULL,
            endpoint TEXT NOT NULL,
            ready INTEGER NOT NULL CHECK (ready IN (0, 1))
        );

        CREATE TABLE webhook_suppression (
            suppression_id INTEGER PRIMARY KEY,
            topic_key TEXT NOT NULL,
            delivery_id INTEGER,
            reason TEXT NOT NULL
        );
        """
    )
    return db


def test_email_batch_keeps_eligible_recipients_in_order():
    db = make_db()
    db.executemany(
        "INSERT INTO email_recipient VALUES (?, 'spring', ?, ?)",
        [(1, "a@example.test", 1), (2, "b@example.test", 1), (3, "c@example.test", 0)],
    )
    db.execute(
        "INSERT INTO email_suppression VALUES (1, 'spring', 2, 'opt-out')"
    )

    rows = db.execute(
        read_sql("select_email_batch.sql"),
        {"campaign_key": "spring"},
    ).fetchall()

    assert len(rows) == 1
    assert rows == [(1, "a@example.test")]


def test_webhook_batch_keeps_ready_deliveries_in_order():
    db = make_db()
    db.executemany(
        "INSERT INTO webhook_delivery VALUES (?, 'spring', ?, ?)",
        [(10, "https://one.test/hook", 1), (11, "https://two.test/hook", 1), (12, "https://three.test/hook", 0)],
    )
    db.execute(
        "INSERT INTO webhook_suppression VALUES (1, 'spring', 11, 'paused')"
    )

    rows = db.execute(
        read_sql("select_webhook_batch.sql"),
        {"topic_key": "spring"},
    ).fetchall()

    assert len(rows) == 1
    assert rows == [(10, "https://one.test/hook")]


def test_suppression_review_lists_both_channels():
    db = make_db()
    db.execute(
        "INSERT INTO email_suppression VALUES (1, 'spring', 2, 'opt-out')"
    )
    db.execute(
        "INSERT INTO webhook_suppression VALUES (1, 'spring', 11, 'paused')"
    )

    rows = db.execute(
        read_sql("list_suppression_feed.sql"),
        {"scope_key": "spring"},
    ).fetchall()

    assert len(rows) == 2
    assert rows == [
        ("email", "spring", 2, "opt-out"),
        ("webhook", "spring", 11, "paused"),
    ]
